/*
  DilAvatar v13 — Kare Tabanlı Canlı Konuşan Avatar
  -------------------------------------------------
  Bu sürüm foto-kare mantığıyla çalışır:
  - 9 konuşma/göz karesi
  - 4 saç düzeltme karesi
  - konuşurken sağ-sol / öne-arkaya mikro baş hareketi
  - doğal göz kırpma: normal -> yarı kapalı -> kapalı -> yarı kapalı -> normal
  - çevrimdışı, tek avatar.js, dış bağımlılık yok

  API:
    DilAvatar.mount(elementIdVeyaEleman, options?)
    DilAvatar.setMouth(shape)
    DilAvatar.speakText(text, durationMs?)
    DilAvatar.thinking(on)
    DilAvatar.stop()
    DilAvatar.blink()
    DilAvatar.fixHair()
    DilAvatar.setGender("erkek")
    DilAvatar.getGender()
    DilAvatar.setHeadMotion(true|false)
    DilAvatar.setAutoHair(true|false)

  Not:
    Gerçek ses dalgasına bağlı lip-sync değildir.
    Metin harf harf süreye yayılır ve her harf uygun foto-kareye eşlenir.
*/
(function(global) {
  "use strict";

  var STORAGE_KEY = "DilAvatar.frame.v13.settings";

  var FR = {"rest": "data:image/webp;base64,", "slight": "data:image/webp;base64,", "half": "data:image/webp;base64,", "mid": "data:image/webp;base64,", "open": "data:image/webp;base64,", "round": "data:image/webp;base64,", "wide": "data:image/webp;base64,", "blinkHalf": "data:image/webp;base64,", "blink": "data:image/webp;base64,", "hairDown": "data:image/webp;base64,", "hairNear": "data:image/webp;base64,", "hairTouch": "data:image/webp;base64,", "hairSmooth": "data:image/webp;base64,"};

  var state = {
    host: null,
    root: null,
    frame: null,
    stage: null,
    img: null,
    currentFrame: "rest",
    lastSpeechFrame: "rest",
    gender: "erkek",
    speaking: false,
    thinking: false,
    hairActive: false,
    headMotion: true,
    autoHair: true,
    motionMode: "idle",
    speechTimer: null,
    thinkingTimer: null,
    blinkTimer: null,
    blinkSequenceTimer: null,
    hairTimer: null,
    autoHairTimer: null,
    motionRaf: null,
    mountedAt: 0,
    opts: {
      size: 300,
      borderColor: "#2dd4bf",
      showSwitch: false,
      showMiniControls: false
    }
  };

  function safeGet(key, fallback) {
    try {
      var v = global.localStorage && global.localStorage.getItem(key);
      return v == null ? fallback : v;
    } catch(e) {
      return fallback;
    }
  }

  function safeSet(key, value) {
    try {
      if (global.localStorage) global.localStorage.setItem(key, value);
    } catch(e) {}
  }

  function loadSettings() {
    try {
      var saved = JSON.parse(safeGet(STORAGE_KEY, "{}") || "{}");
      if (typeof saved.headMotion === "boolean") state.headMotion = saved.headMotion;
      if (typeof saved.autoHair === "boolean") state.autoHair = saved.autoHair;
    } catch(e) {}
  }

  function saveSettings() {
    safeSet(STORAGE_KEY, JSON.stringify({
      headMotion: state.headMotion,
      autoHair: state.autoHair
    }));
  }

  function injectCss() {
    if (document.getElementById("dil-avatar-v13-style")) return;

    var css = `
      .dil-avatar-v13 {
        --da-border:#2dd4bf;
        width:100%;
        max-width:var(--da-size, 300px);
        min-width:120px;
        margin:0 auto;
        font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;
        color:#e5e7eb;
        user-select:none;
      }
      .dil-avatar-v13-frame {
        width:100%;
        aspect-ratio:1/1;
        position:relative;
        overflow:hidden;
        border-radius:50%;
        background:#0b1120;
        border:4px solid var(--da-border);
        box-shadow:0 20px 42px rgba(0,0,0,.30), inset 0 0 0 1px rgba(255,255,255,.08);
        transform:translateZ(0);
      }
      .dil-avatar-v13-stage {
        position:absolute;
        inset:-2.5%;
        width:105%;
        height:105%;
        transform-origin:50% 54%;
        will-change:transform;
      }
      .dil-avatar-v13-img {
        width:100%;
        height:100%;
        object-fit:cover;
        object-position:center center;
        display:block;
        pointer-events:none;
        -webkit-user-drag:none;
      }
      .dil-avatar-v13-switch,
      .dil-avatar-v13-mini {
        margin:12px auto 0;
        display:flex;
        gap:8px;
        align-items:center;
        justify-content:center;
        flex-wrap:wrap;
      }
      .dil-avatar-v13-switch button,
      .dil-avatar-v13-mini button {
        border:0;
        border-radius:14px;
        padding:10px 13px;
        cursor:pointer;
        font-weight:800;
        color:white;
        background:linear-gradient(135deg,#2563eb,#3b82f6);
      }
      .dil-avatar-v13-mini button.secondary {
        background:#1e293b;
        color:#dbeafe;
      }
      .dil-avatar-v13-badge {
        display:inline-flex;
        padding:6px 10px;
        border-radius:999px;
        background:rgba(15,23,42,.78);
        border:1px solid rgba(148,163,184,.25);
        color:#93c5fd;
        font-size:12px;
        font-weight:800;
      }
    `;

    var style = document.createElement("style");
    style.id = "dil-avatar-v13-style";
    style.textContent = css;
    document.head.appendChild(style);
  }

  function preloadFrames() {
    Object.keys(FR).forEach(function(k) {
      var im = new Image();
      im.src = FR[k];
    });
  }

  function resolveTarget(target) {
    if (typeof target === "string") return document.getElementById(target);
    return target;
  }

  function mount(target, options) {
    loadSettings();
    injectCss();
    preloadFrames();

    var host = resolveTarget(target);
    if (!host) throw new Error("DilAvatar.mount: hedef eleman bulunamadı.");

    state.opts = Object.assign({}, state.opts, options || {});
    host.innerHTML = "";

    var root = document.createElement("div");
    root.className = "dil-avatar-v13";
    root.style.setProperty("--da-size", (state.opts.size || 300) + "px");
    root.style.setProperty("--da-border", state.opts.borderColor || "#2dd4bf");

    var frame = document.createElement("div");
    frame.className = "dil-avatar-v13-frame";

    var stage = document.createElement("div");
    stage.className = "dil-avatar-v13-stage";

    var img = document.createElement("img");
    img.className = "dil-avatar-v13-img";
    img.alt = "DilAvatar konuşan asistan";
    img.src = FR.rest;

    stage.appendChild(img);
    frame.appendChild(stage);
    root.appendChild(frame);

    if (state.opts.showSwitch) {
      var sw = document.createElement("div");
      sw.className = "dil-avatar-v13-switch";
      var badge = document.createElement("span");
      badge.className = "dil-avatar-v13-badge";
      badge.textContent = "Erkek Avatar";
      sw.appendChild(badge);
      root.appendChild(sw);
    }

    if (state.opts.showMiniControls) {
      var mini = document.createElement("div");
      mini.className = "dil-avatar-v13-mini";
      mini.innerHTML = `
        <button type="button" data-da-act="speak">Konuş</button>
        <button type="button" data-da-act="blink" class="secondary">Göz kırp</button>
        <button type="button" data-da-act="hair" class="secondary">Saç düzelt</button>
        <button type="button" data-da-act="stop" class="secondary">Dur</button>
      `;
      mini.addEventListener("click", function(ev) {
        var b = ev.target.closest("button");
        if (!b) return;
        var act = b.getAttribute("data-da-act");
        if (act === "speak") speakText("merhaba bugün ingilizce çalışıyoruz", 3200);
        if (act === "blink") blink();
        if (act === "hair") fixHair();
        if (act === "stop") stop();
      });
      root.appendChild(mini);
    }

    host.appendChild(root);

    state.host = host;
    state.root = root;
    state.frame = frame;
    state.stage = stage;
    state.img = img;
    state.mountedAt = Date.now();
    state.currentFrame = "rest";
    state.lastSpeechFrame = "rest";

    setMotionMode("idle");
    scheduleBlink();
    scheduleAutoHair();

    return root;
  }

  function displayFrame(name, rememberSpeech) {
    if (!FR[name]) name = "rest";
    if (!state.img) return;

    state.currentFrame = name;
    state.img.src = FR[name];

    if (rememberSpeech !== false && !/^hair/.test(name) && name !== "blink" && name !== "blinkHalf") {
      state.lastSpeechFrame = name;
    }
  }

  function mouthToFrame(shape) {
    switch(shape) {
      case "rest": return "rest";
      case "closed": return "rest";
      case "slight": return "slight";
      case "half": return "half";
      case "mid": return "mid";
      case "open": return "open";
      case "round": return "round";
      case "wide": return "wide";
      case "teeth": return "mid";
      default: return "rest";
    }
  }

  function setMouth(shape) {
    if (state.hairActive) return;
    displayFrame(mouthToFrame(shape));
  }

  function visemeForChar(ch) {
    ch = String(ch || "").toLocaleLowerCase("tr-TR");

    // Türkçe okunuş mantığı
    if (ch === "a" || ch === "â") return "open";
    if (ch === "e") return "wide";
    if (ch === "o" || ch === "u") return "round";
    if (ch === "ı" || ch === "i" || ch === "ü" || ch === "ö" || ch === "y") return "wide";
    if (ch === "m" || ch === "b" || ch === "p") return "closed";
    if (ch === "f" || ch === "v") return "teeth";
    if (/\s/.test(ch)) return "rest";

    // Ünsüzlerde hafif ağız aralığı daha canlı duruyor.
    if ("çcğhjklmnprsştzqxw".indexOf(ch) >= 0) return "slight";

    return "rest";
  }

  function frameForChar(ch, index) {
    var v = visemeForChar(ch);
    var f = mouthToFrame(v);

    // Konuşma sırasında aynı kare çok uzun kalmasın diye bazı ünsüzleri değiştir.
    if (f === "slight" && index % 3 === 0) f = "half";
    return f;
  }

  function clearTimer(t) {
    if (t) clearTimeout(t);
    return null;
  }

  function clearIntervalTimer(t) {
    if (t) clearInterval(t);
    return null;
  }

  function speakText(text, durationMs) {
    stopSpeechOnly();
    text = String(text || "");
    var chars = Array.prototype.slice.call(text);

    if (!chars.length) {
      displayFrame("rest");
      setMotionMode("idle");
      return;
    }

    state.speaking = true;
    state.hairActive = false;
    setMotionMode("talk");

    var total = Number(durationMs);
    var per = total && isFinite(total) ? total / chars.length : 110;
    per = Math.max(60, Math.min(150, per));

    var i = 0;

    function step() {
      if (!state.speaking || i >= chars.length) {
        state.speaking = false;
        displayFrame("rest");
        setMotionMode("idle");
        scheduleAutoHair();
        return;
      }

      var frame = frameForChar(chars[i], i);
      displayFrame(frame);
      i += 1;
      state.speechTimer = setTimeout(step, per);
    }

    step();
  }

  function stopSpeechOnly() {
    state.speechTimer = clearTimer(state.speechTimer);
    state.speaking = false;
  }

  function blink() {
    if (!state.img || state.hairActive) return;

    var back = state.lastSpeechFrame || "rest";
    state.blinkSequenceTimer = clearTimer(state.blinkSequenceTimer);

    displayFrame("blinkHalf", false);
    state.blinkSequenceTimer = setTimeout(function() {
      displayFrame("blink", false);
      state.blinkSequenceTimer = setTimeout(function() {
        displayFrame("blinkHalf", false);
        state.blinkSequenceTimer = setTimeout(function() {
          displayFrame(back, false);
        }, 70);
      }, 80);
    }, 65);
  }

  function scheduleBlink() {
    state.blinkTimer = clearTimer(state.blinkTimer);
    var next = 2600 + Math.random() * 3200;
    state.blinkTimer = setTimeout(function() {
      blink();
      scheduleBlink();
    }, next);
  }

  function fixHair(force) {
    if (!state.img) return;
    if (state.speaking && !force) return;

    state.hairActive = true;
    state.speaking = false;
    state.speechTimer = clearTimer(state.speechTimer);
    setMotionMode("hair");

    var seq = [
      ["hairDown", 130],
      ["hairNear", 150],
      ["hairTouch", 180],
      ["hairSmooth", 260],
      ["hairTouch", 170],
      ["hairNear", 150],
      ["hairDown", 130],
      ["rest", 100]
    ];

    var i = 0;
    state.hairTimer = clearTimer(state.hairTimer);

    function step() {
      if (i >= seq.length) {
        state.hairActive = false;
        displayFrame("rest");
        setMotionMode("idle");
        scheduleAutoHair();
        return;
      }
      displayFrame(seq[i][0], false);
      state.hairTimer = setTimeout(step, seq[i][1]);
      i += 1;
    }

    step();
  }

  function scheduleAutoHair() {
    state.autoHairTimer = clearTimer(state.autoHairTimer);
    if (!state.autoHair) return;

    var next = 22000 + Math.random() * 18000;
    state.autoHairTimer = setTimeout(function() {
      if (!state.speaking && !state.thinking && !state.hairActive) fixHair(true);
      scheduleAutoHair();
    }, next);
  }

  function thinking(on) {
    state.thinking = !!on;
    state.thinkingTimer = clearIntervalTimer(state.thinkingTimer);

    if (!on) {
      displayFrame("rest");
      setMotionMode("idle");
      return;
    }

    setMotionMode("think");
    var flip = false;
    state.thinkingTimer = setInterval(function() {
      if (state.hairActive) return;
      flip = !flip;
      displayFrame(flip ? "slight" : "rest");
    }, 620);
  }

  function setMotionMode(mode) {
    state.motionMode = mode || "idle";
    startMotionLoop();
  }

  function startMotionLoop() {
    if (state.motionRaf) return;

    function loop() {
      state.motionRaf = requestAnimationFrame(loop);
      applyHeadMotion();
    }
    state.motionRaf = requestAnimationFrame(loop);
  }

  function applyHeadMotion() {
    if (!state.stage) return;

    if (!state.headMotion) {
      state.stage.style.transform = "translate3d(0,0,0) rotate(0deg) scale(1)";
      return;
    }

    var t = performance.now();
    var x = 0, y = 0, r = 0, s = 1;

    if (state.motionMode === "talk") {
      // Konuşurken: çok hafif sağ-sol ve öne-arkaya.
      x = Math.sin(t * 0.0060) * 3.0 + Math.sin(t * 0.014) * 0.9;
      y = Math.sin(t * 0.0090) * 2.2 + 2.0;
      r = Math.sin(t * 0.0048) * 1.15;
      s = 1.012 + Math.sin(t * 0.0065) * 0.004;
    } else if (state.motionMode === "think") {
      // Düşünürken: daha yavaş, hafif sağ-sol.
      x = Math.sin(t * 0.0023) * 3.5;
      y = Math.sin(t * 0.0028) * 1.2;
      r = Math.sin(t * 0.0020) * 1.25;
      s = 1.006;
    } else if (state.motionMode === "hair") {
      // Saç düzeltirken: gövde çok az öne gelir.
      x = Math.sin(t * 0.004) * 1.6;
      y = 3 + Math.sin(t * 0.006) * 1.0;
      r = Math.sin(t * 0.003) * 0.8;
      s = 1.018;
    } else {
      // Idle nefes / mikro hareket.
      x = Math.sin(t * 0.0018) * 1.4;
      y = Math.sin(t * 0.0020) * 1.1;
      r = Math.sin(t * 0.0015) * 0.55;
      s = 1.004 + Math.sin(t * 0.0016) * 0.002;
    }

    state.stage.style.transform =
      "translate3d(" + x.toFixed(2) + "px," + y.toFixed(2) + "px,0) " +
      "rotate(" + r.toFixed(3) + "deg) " +
      "scale(" + s.toFixed(4) + ")";
  }

  function stop() {
    stopSpeechOnly();
    state.thinking = false;
    state.hairActive = false;
    state.thinkingTimer = clearIntervalTimer(state.thinkingTimer);
    state.hairTimer = clearTimer(state.hairTimer);
    state.blinkSequenceTimer = clearTimer(state.blinkSequenceTimer);
    displayFrame("rest");
    setMotionMode("idle");
  }

  function setGender(g) {
    // Bu paket erkek avatar için üretildi; API uyumluluğu için tutuluyor.
    state.gender = "erkek";
    return state.gender;
  }

  function getGender() {
    return "erkek";
  }

  function setHeadMotion(on) {
    state.headMotion = !!on;
    saveSettings();
    applyHeadMotion();
  }

  function setAutoHair(on) {
    state.autoHair = !!on;
    saveSettings();
    scheduleAutoHair();
  }

  function getFrameNames() {
    return Object.keys(FR).slice();
  }

  function showFrame(name) {
    displayFrame(name || "rest", false);
  }

  global.DilAvatar = {
    mount: mount,
    setMouth: setMouth,
    speakText: speakText,
    thinking: thinking,
    stop: stop,
    blink: blink,
    fixHair: fixHair,
    setGender: setGender,
    getGender: getGender,
    setHeadMotion: setHeadMotion,
    setAutoHair: setAutoHair,
    visemeForChar: visemeForChar,
    showFrame: showFrame,
    getFrameNames: getFrameNames
  };

})(window);
